<template>
  <div>
    <div class="grid-section-title">
      {{ title }}
      <el-tag v-if="tag" size="mini" type="warning" class="grid-tag">{{ tag }}</el-tag>
    </div>
    <el-row :gutter="12">
      <el-col v-for="item in tools" :key="item.id" :span="8" class="grid-col">
        <el-card class="grid-card" :class="{ 'grid-card--member': isMember !== undefined }" shadow="hover" @click.native="$emit('tool-click', item)">
          <div class="grid-icon">
            <i :class="item.icon"></i>
          </div>
          <div class="grid-name">{{ item.name }}</div>
          <i v-if="isMember !== undefined" :class="isMember ? 'el-icon-unlock lock-icon lock-icon--open' : 'el-icon-lock lock-icon'"></i>
        </el-card>
      </el-col>
    </el-row>
  </div>
</template>

<script>
export default {
  name: 'ToolGrid',
  props: {
    title: { type: String, required: true },
    tag: { type: String, default: '' },
    tools: { type: Array, default: () => [] },
    // 传 undefined 表示不显示锁图标（免费板块），传 true/false 控制锁/解锁
    isMember: { type: Boolean, default: undefined }
  }
};
</script>

